challenges.solution:
in vec2 v_uv;
uniform float u_time;
out vec4 fragColor;

void main() {
    // Build a 2D rotation matrix from u_time
    float c = cos(u_time);
    float s = sin(u_time);
    mat2 rot = mat2(c, -s, s, c);

    // Rotate UV around center (0.5, 0.5) using * operator
    vec2 centered = v_uv - 0.5;
    vec2 rotated  = rot * centered;
    vec2 result   = rotated + 0.5;

    fragColor = vec4(result, 0.5, 1.0);
}

hlsl.code:
cbuffer Uniforms : register(b0) {
    float u_time;
};

float4 main(float2 uv : TEXCOORD0) : SV_Target {
    float c = cos(u_time);
    float s = sin(u_time);
    float2x2 rot = float2x2(c, -s, s, c);
    float2 centered = uv - 0.5;
    float2 rotated  = mul(rot, centered);
    float2 result   = rotated + 0.5;
    return float4(result, 0.5, 1.0);
}

